const https = require("https");
const http  = require("http");
const fs    = require("fs");
const path  = require("path");
const url   = require("url");

const PORT         = process.env.PORT || 3000;
const IDEOGRAM_KEY = process.env.IDEOGRAM_API_KEY || "";
const IMG_B64      = "";

function fetchUrl(imgUrl, cb) {
  var u = new url.URL(imgUrl);
  var mod = u.protocol === "https:" ? https : http;
  var chunks = [];
  mod.get(imgUrl, function(res) {
    res.on("data", function(c){ chunks.push(c); });
    res.on("end", function(){ cb(null, Buffer.concat(chunks)); });
  }).on("error", cb);
}

function layerizeText(cb) {
  var imgBuffer = Buffer.from(IMG_B64, "base64");
  var boundary = "----NKB" + Date.now().toString(36);
  var CRLF = "\r\n";

  var imgPart = Buffer.concat([
    Buffer.from(
      "--"+boundary+CRLF+
      "Content-Disposition: form-data; name=\"image\"; filename=\"template.jpg\""+CRLF+
      "Content-Type: image/jpeg"+CRLF+CRLF,
      "utf8"
    ),
    imgBuffer,
    Buffer.from(CRLF+"--"+boundary+"--"+CRLF, "utf8")
  ]);

  console.log("Calling Layerize Text...");

  var req = https.request({
    hostname: "api.ideogram.ai",
    path: "/v1/ideogram-v3/layerize-text",
    method: "POST",
    headers: {
      "Api-Key": IDEOGRAM_KEY,
      "Content-Type": "multipart/form-data; boundary="+boundary,
      "Content-Length": imgPart.length
    }
  }, function(res) {
    var data = "";
    res.on("data", function(c){ data += c; });
    res.on("end", function() {
      console.log("Layerize status:", res.statusCode, data.substring(0,300));
      try {
        var j = JSON.parse(data);
        if (res.statusCode !== 200) return cb(new Error(j.detail || j.message || data.substring(0,200)));
        if (!j.base_image_url) return cb(new Error("No base_image_url: "+data.substring(0,200)));
        cb(null, j.base_image_url, j.text_blocks || [], j.original_image_url);
      } catch(e) { cb(new Error("Parse error: "+data.substring(0,200))); }
    });
  });
  req.on("error", cb);
  req.write(imgPart);
  req.end();
}

var server = http.createServer(function(req, res) {
  var p = url.parse(req.url).pathname;
  res.setHeader("Access-Control-Allow-Origin","*");
  res.setHeader("Access-Control-Allow-Headers","Content-Type");
  if (req.method === "OPTIONS") { res.writeHead(200); res.end(); return; }

  if (req.method === "GET" && p === "/") {
    fs.readFile(path.join(__dirname,"public","index.html"), function(err, data) {
      if (err) { res.writeHead(404); res.end("Not found"); return; }
      res.setHeader("Content-Type","text/html");
      res.writeHead(200); res.end(data);
    });
    return;
  }

  if (req.method === "POST" && p === "/api/generate") {
    if (!IDEOGRAM_KEY) {
      res.writeHead(500);
      res.end(JSON.stringify({error:"IDEOGRAM_API_KEY not configured"}));
      return;
    }
    var body = "";
    req.on("data", function(c){ body += c; });
    req.on("end", function() {
      var ev;
      try { ev = JSON.parse(body); } catch(e) {
        res.writeHead(400); res.end(JSON.stringify({error:"Invalid JSON"})); return;
      }

      // Step 1: Layerize - remove text from template
      layerizeText(function(err, bgUrl, textBlocks, origUrl) {
        if (err) {
          console.error("Layerize error:", err.message);
          res.writeHead(500);
          res.end(JSON.stringify({error:"Layerize failed: "+err.message}));
          return;
        }

        // Step 2: Fetch clean background as base64
        fetchUrl(bgUrl, function(err2, bgBuffer) {
          if (err2) {
            res.writeHead(500);
            res.end(JSON.stringify({error:"Fetch bg failed: "+err2.message}));
            return;
          }

          console.log("Got clean bg:", bgBuffer.length, "bytes");
          console.log("Text blocks:", JSON.stringify(textBlocks.slice(0,3)));

          // Step 3: Send bg + text_blocks + event data to client for Canvas rendering
          res.setHeader("Content-Type","application/json");
          res.writeHead(200);
          res.end(JSON.stringify({
            bg_b64: bgBuffer.toString("base64"),
            text_blocks: textBlocks,
            event: ev
          }));
        });
      });
    });
    return;
  }

  res.writeHead(404); res.end("Not found");
});

server.timeout = 120000;
server.listen(PORT, function(){ console.log("NightKit Layerize+Canvas on port "+PORT); });
